import Link from "next/link";

// project
import Logo from "@/components/uiable/layout/shared/logo";

// assets
import { Chrome, Facebook, Instagram, Slack, Twitter } from "lucide-react";

// constants
const footerLinks = [
  { label: "About Us", href: "#" },
  { label: "Services", href: "#" },
  { label: "Term & Condition", href: "#" },
  { label: "Privacy", href: "#" }
];

//  ------------------------------ | FOOTER - 6 | ------------------------------  //

export default function Footer6() {
  return (
    <footer className="py-16 md:py-20">
      <div className="container mx-auto px-4">
        <div className="grid grid-cols-12 gap-y-6 md:gap-6 items-start">
          {/* Brand Section */}
          <div className="col-span-12 md:col-span-6 flex flex-col gap-6">
            <Logo />
            <p className="text-slate-500 max-w-sm">
              At half-past eight the door opened, the policeman appeared At
              half-past eight.
            </p>
          </div>

          {/* Navigation & Social Section */}
          <div className="col-span-12 md:col-span-6 flex flex-col md:items-end gap-6">
            {/* Quick Links */}
            <nav className="flex flex-wrap items-center gap-x-6 gap-y-6 justify-start md:justify-end">
              {footerLinks.map((link) => (
                <Link
                  key={link.label}
                  href={link.href}
                  className="text-slate-500 hover:text-primary transition-colors text-md font-medium"
                >
                  {link.label}
                </Link>
              ))}
            </nav>

            {/* Social Links */}
            <div className="flex flex-wrap items-center gap-4">
              {/* Slack */}
              <Link
                href="#"
                aria-label="Slack"
                className="flex h-10 w-10 items-center justify-center rounded-full bg-amber-100 text-amber-600 transition-all hover:scale-105 hover:bg-amber-500 hover:text-white"
              >
                <Slack className="h-5 w-5" />
              </Link>

              {/* Twitter */}
              <Link
                href="#"
                aria-label="Twitter"
                className="flex h-10 w-10 items-center justify-center rounded-full bg-sky-100 text-sky-500 transition-all hover:scale-105 hover:bg-sky-500 hover:text-white"
              >
                <Twitter className="h-5 w-5" />
              </Link>

              {/* Facebook */}
              <Link
                href="#"
                aria-label="Facebook"
                className="flex h-10 w-10 items-center justify-center rounded-full bg-blue-100 text-blue-600 transition-all hover:scale-105 hover:bg-blue-600 hover:text-white"
              >
                <Facebook className="h-5 w-5" />
              </Link>

              {/* Chrome */}
              <Link
                href="#"
                aria-label="Chrome"
                className="flex h-10 w-10 items-center justify-center rounded-full bg-red-100 text-red-500 transition-all hover:scale-105 hover:bg-red-500 hover:text-white"
              >
                <Chrome className="h-5 w-5" />
              </Link>

              {/* Instagram */}
              <Link
                href="#"
                aria-label="Instagram"
                className="flex h-10 w-10 items-center justify-center rounded-full bg-pink-100 text-pink-500 transition-all hover:scale-105 hover:bg-pink-500 hover:text-white"
              >
                <Instagram className="h-5 w-5" />
              </Link>
            </div>
          </div>
        </div>
      </div>
    </footer>
  );
}
